import theme from '../theme'

const Link = ({ link, title }) => {
    return (
        <div className='work-link'>
            <style>{style}</style>
            <li>
                <a target="_blank" href={link}>{title}</a>
            </li>
        </div>
    )
}

const style = `
  .work-link a {
    color:grey;
    text-decoration:none;
  }
  .work-link a:hover {
    color:white;
  }
`

export default Link
